python3 -c "
import sys, json, re, subprocess, os, ast
try:
    payload = json.load(sys.stdin)
    path = payload.get('tool_input', {}).get('file_path', '')
    if not path or not os.path.exists(path):
        sys.exit(0)
    ext = os.path.splitext(path)[1]

    # 1. Emoji check
    EMOJI = re.compile(r'[\U0001F000-\U0001FFFF\U0001F900-\U0001F9FF\U0001FA00-\U0001FAFF\U00002600-\U000026FF\U00002700-\U000027BF]+')
    with open(path, encoding='utf-8', errors='replace') as f:
        for i, line in enumerate(f, 1):
            if EMOJI.search(line):
                print(f'[WARN] Emoji detected in {path}:{i} - pre-commit will block this file', file=sys.stderr)
                break

    if ext == '.py':
        with open(path, encoding='utf-8', errors='replace') as f:
            source = f.read()

        # 2. Python syntax check
        result = subprocess.run(
            ['python3', '-m', 'py_compile', path],
            capture_output=True, text=True, timeout=10
        )
        if result.returncode != 0:
            print(f'[ERROR] Python syntax error in {path}:', file=sys.stderr)
            print(result.stderr.strip(), file=sys.stderr)

        # 3. MT001: os.getenv direct call
        canonical = path.replace(os.sep, '/')
        if not canonical.endswith(('config/settings.py', 'config/db.py')):
            try:
                tree = ast.parse(source)
                for node in ast.walk(tree):
                    if (
                        isinstance(node, ast.Call)
                        and isinstance(node.func, ast.Attribute)
                        and node.func.attr == 'getenv'
                        and isinstance(node.func.value, ast.Name)
                        and node.func.value.id == 'os'
                    ):
                        print(f'[WARN] MT001 {path}:{node.lineno} os.getenv() - use config/settings.py', file=sys.stderr)
            except SyntaxError:
                pass

        # 4. MT002: SQL INSERT field/value count mismatch
        insert_re = re.compile(r'INSERT\s+(?:INTO\s+)?\w+\s*\(([^)]+)\)\s*VALUES\s*\(([^)]+)\)', re.IGNORECASE)
        for i, line in enumerate(source.splitlines(), 1):
            if 'INSERT' in line.upper() and 'VALUES' in line.upper():
                for m in insert_re.finditer(line):
                    nf = len([x for x in m.group(1).split(',') if x.strip()])
                    nv = len([x for x in m.group(2).split(',') if x.strip()])
                    if nf != nv:
                        print(f'[WARN] MT002 {path}:{i} INSERT fields({nf}) != VALUES({nv})', file=sys.stderr)

except Exception:
    pass
"
